class _Node:
    __slots__ = ("val", "left", "right")

    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None


def _build(root_arr):
    if not root_arr or root_arr[0] is None:
        return None
    n = len(root_arr)
    root = _Node(0)
    queue = [root]
    i = 1
    while queue and i < n:
        node = queue.pop(0)
        if i < n:
            if root_arr[i] is not None:
                node.left = _Node(2 * node.val + 1)
                queue.append(node.left)
            i += 1
        if i < n:
            if root_arr[i] is not None:
                node.right = _Node(2 * node.val + 2)
                queue.append(node.right)
            i += 1
    return root


def _collect(node, out):
    if node is None:
        return
    out.add(node.val)
    _collect(node.left, out)
    _collect(node.right, out)


class FindElements:
    def __init__(self, root):
        tree = _build(root)
        vals = set()
        _collect(tree, vals)
        self.values = vals

    def find(self, target):
        return target in self.values

