class FindElements {
    constructor(root) {
        const seen = new Set();
        if (root.length && root[0] !== null) {
            seen.add(0);
            const queue = [0];
            let i = 1;
            const n = root.length;
            while (queue.length && i < n) {
                const val = queue.shift();
                if (i < n) {
                    if (root[i] !== null) {
                        const lv = 2 * val + 1;
                        seen.add(lv);
                        queue.push(lv);
                    }
                    i += 1;
                }
                if (i < n) {
                    if (root[i] !== null) {
                        const rv = 2 * val + 2;
                        seen.add(rv);
                        queue.push(rv);
                    }
                    i += 1;
                }
            }
        }
        this.seen = seen;
    }
    find(target) {
        return this.seen.has(target);
    }
}
